// CONSULTAR API CEAM AUDITOR
// Dispara el webscraper para fichas y devuelve el delta de suspendidas
const API_URL = 'https://auditor.sekaitech.com.pe';
const CEAM_TOKEN = 'token_aqui_si_aplica';

let result;
try {
  result = await this.helpers.httpRequest({
    method: 'GET',
    url: API_URL + '/api/v1/fichas/alertas-suspendidas',
    headers: {
      'Accept': 'application/json'
    },
    timeout: 300000, // 5 MINUTOS (porque Playwright puede tardar en scrapear)
    json: true
  });
  if (typeof result === 'string') result = JSON.parse(result);
} catch(e) {
  return [{ json: { error: true, message: e.message } }];
}

return [{ json: result }];

// NOTIFICAR ERROR VIA EVOLUTION API
const EVOLUTION_URL      = 'https://evolution.sekaitech.com.pe';
const EVOLUTION_API_KEY  = '6mF28RqtJdPIZorVIbAaRBiKZoZr3a5t4d9jikNna7c=';
const EVOLUTION_INSTANCE = 'sekaitech';
const GROUP_JID          = '120363423813951789@g.us';

const inp  = $input.item.json;
const errorMsg = inp.message || inp.error || 'Error desconocido';
const ahora = new Date().toLocaleString('es-PE', { timeZone: 'America/Lima' });

const texto = `⚠️ *ERROR — CEAM Auditor Scraper (Fichas)*\n🗓️ ${ahora}\n────────────────────────────────────\nEl proceso de extracción de catálogo falló.\n\nError: ${errorMsg}\n\nRevisa los logs en el contenedor del backend.`;

try {
