return [{ json: { notified: true, error: errorMsg } }];

// =================================================================
//  PROCESAR DELTAS DE FICHAS (AGRUPADOS POR MARCA)
// =================================================================
let data = $input.first().json;

// Manejar estructuras anidadas si existe
if (data.body) data = data.body;
if (data.data) data = data.data;

if (!data || !data.hayAlertas || !data.datos || Object.keys(data.datos).length === 0) {
  return [{ json: { hayAlertas: "false", mensajes: [], total: 0 } }];
}

const sep = '─'.repeat(30);
const mensajes = [];
let totalSuspendidas = 0;

// El backend enviará: datos: { "Kenya": [{nro_parte: "123", descripcion: "..."}] }
// y opcionalmente resumen: { "Kenya": { ofertadas_actuales: 34 } }

let header = [
  '⚠️ *ALERTAS DE CATÁLOGO: FICHAS SUSPENDIDAS*',
  '🗓️ ' + new Date().toLocaleString('es-PE', { timeZone: 'America/Lima' }),
  sep,
  '🚨 El escaner detectó los siguientes cambios:'
];

mensajes.push(header.join('\n'));

const marcas = Object.keys(data.datos);
for (const marca of marcas) {
  const fichas = data.datos[marca];
  if (fichas && fichas.length > 0) {
    totalSuspendidas += fichas.length;

    // Si el backend provee la cuota de ofertadas restantes, la mostramos
    let infoResumen = '';
    if (data.resumen && data.resumen[marca]) {
      const ofertadas = data.resumen[marca].ofertadas_actuales;
      infoResumen = ` (Quedan ${ofertadas} ofertadas)`;
    }

    let bloque = [];
    bloque.push(`\n🏬 *MARCA: ${marca.toUpperCase()}*${infoResumen}`);

    fichas.forEach((f, i) => {
       bloque.push(`   ❌ *${i + 1}.* P/N: *${f.nro_parte}*`);
       if (f.descripcion) bloque.push(`      ↳ ${f.descripcion}`);
    });

    mensajes.push(bloque.join('\n'));
  }
}

mensajes.push('\n' + sep + '\n🤖 _CEAM Auditor Automático_');

return [{ json: { hayAlertas: "true", mensajes: [mensajes.join('\n')], total: totalSuspendidas } }];

// ENVIAR VIA EVOLUTION API → GRUPO WHATSAPP CEAM
const EVOLUTION_URL      = 'https://evolution.sekaitech.com.pe';
const EVOLUTION_API_KEY  = '6mF28RqtJdPIZorVIbAaRBiKZoZr3a5t4d9jikNna7c=';
const EVOLUTION_INSTANCE = 'sekaitech';
const GROUP_JID          = '120363423813951789@g.us';

let results = [];

for (const item of $input.all()) {
  const mensaje = item.json.mensaje || '';
  if (!mensaje) continue;

  try {
    const r = await this.helpers.httpRequest({
      method: 'POST',
      url: EVOLUTION_URL + '/message/sendText/' + EVOLUTION_INSTANCE,
      headers: {
        'apikey': EVOLUTION_API_KEY,
        'Content-Type': 'application/json'
      },
      body: {
        number: GROUP_JID,
        text: mensaje
      },
      json: true,
      timeout: 15000
    });
    results.push({ json: { success: true, key: r.key } });
    await new Promise(resolve => setTimeout(resolve, 1500));
  } catch(e) {
    results.push({ json: { success: false, error: e.message } });
  }
}

return results;
